import React, {useCallback, useMemo, useState} from 'react';
import {ActivityIndicator, StyleSheet, Text, View} from 'react-native';
import {
  NavigationContainer,
  DarkTheme,
  DefaultTheme,
} from '@react-navigation/native';
import {createBottomTabNavigator} from '@react-navigation/bottom-tabs';
import {createNativeStackNavigator} from '@react-navigation/native-stack';
import {useAuth} from '../features/auth/AuthProvider';
import {useTheme} from '../theme/ThemeProvider';
import {useRealtimeNotifications} from '../hooks/useRealtimeNotifications';
import {Toast} from '../components/Toast';
import {LoginScreen} from '../screens/Auth/LoginScreen';
import {SignUpScreen} from '../screens/Auth/SignUpScreen';
import {ForgotPasswordScreen} from '../screens/Auth/ForgotPasswordScreen';
import {HomeFeedScreen} from '../screens/Home/HomeFeedScreen';
import {ExploreScreen} from '../screens/Home/ExploreScreen';
import {NotificationsScreen} from '../screens/Notifications/NotificationsScreen';
import {ProfileScreen} from '../screens/Profile/ProfileScreen';
import {PostDetailScreen} from '../screens/Home/PostDetailScreen';
import {JournalEditorScreen} from '../screens/Editor/JournalEditorScreen';
import {CanvasScreen} from '../screens/Advanced/CanvasScreen';
import {FreedomWallScreen} from '../screens/Advanced/FreedomWallScreen';
import {UniverseScreen} from '../screens/Advanced/UniverseScreen';
import {StoryBrowserScreen} from '../screens/Stories/StoryBrowserScreen';
import {StoryDetailScreen} from '../screens/Stories/StoryDetailScreen';
import {StoryEditorScreen} from '../screens/Stories/StoryEditorScreen';
import {StoryDashboardScreen} from '../screens/Stories/StoryDashboardScreen';
import {StoryLibraryScreen} from '../screens/Stories/StoryLibraryScreen';
import {StoryChapterManagerScreen} from '../screens/Stories/StoryChapterManagerScreen';
import {StoryChapterEditorScreen} from '../screens/Stories/StoryChapterEditorScreen';
import {StoryChapterReaderScreen} from '../screens/Stories/StoryChapterReaderScreen';
import {
  HomeIcon,
  CompassIcon,
  BookIcon,
  BellIcon,
  UserIcon,
} from '../components/icons';
import type {
  AuthStackParamList,
  MainTabParamList,
  RootStackParamList,
} from './types';

const RootStack = createNativeStackNavigator<RootStackParamList>();
const AuthStackNav = createNativeStackNavigator<AuthStackParamList>();
const MainTabs = createBottomTabNavigator<MainTabParamList>();

function AuthNavigator() {
  const {colors} = useTheme();
  return (
    <AuthStackNav.Navigator
      screenOptions={{
        headerStyle: {backgroundColor: colors.bgElevated},
        headerTintColor: colors.textPrimary,
        headerShadowVisible: false,
      }}>
      <AuthStackNav.Screen
        name="Login"
        component={LoginScreen}
        options={{headerShown: false}}
      />
      <AuthStackNav.Screen
        name="SignUp"
        component={SignUpScreen}
        options={{headerShown: false}}
      />
      <AuthStackNav.Screen
        name="ForgotPassword"
        component={ForgotPasswordScreen}
        options={{headerShown: false}}
      />
    </AuthStackNav.Navigator>
  );
}

function MainTabNavigator() {
  const {colors} = useTheme();
  return (
    <MainTabs.Navigator
      screenOptions={{
        headerStyle: {backgroundColor: colors.bgPrimary},
        headerTintColor: colors.textPrimary,
        headerShadowVisible: false,
        tabBarStyle: {
          backgroundColor: colors.bgCard,
          borderTopColor: colors.borderCard,
          borderTopWidth: 1,
          elevation: 0,
        },
        tabBarActiveTintColor: colors.accentAmber,
        tabBarInactiveTintColor: colors.textMuted,
        tabBarLabelStyle: {
          fontSize: 11,
          fontWeight: '600',
        },
      }}>
      <MainTabs.Screen
        name="Home"
        component={HomeFeedScreen}
        options={{
          headerShown: false,
          tabBarIcon: ({color, size}) => <HomeIcon size={size} color={color} />,
        }}
      />
      <MainTabs.Screen
        name="Explore"
        component={ExploreScreen}
        options={{
          tabBarIcon: ({color, size}) => <CompassIcon size={size} color={color} />,
        }}
      />
      <MainTabs.Screen
        name="Stories"
        component={StoryBrowserScreen}
        options={{
          tabBarIcon: ({color, size}) => <BookIcon size={size} color={color} />,
        }}
      />
      <MainTabs.Screen
        name="Notifications"
        component={NotificationsScreen}
        options={{
          tabBarIcon: ({color, size}) => <BellIcon size={size} color={color} />,
        }}
      />
      <MainTabs.Screen
        name="Profile"
        component={ProfileScreen}
        options={{
          tabBarIcon: ({color, size}) => <UserIcon size={size} color={color} />,
        }}
      />
    </MainTabs.Navigator>
  );
}

function LoggedInShell({children}: {children: React.ReactNode}) {
  const {session} = useAuth();
  const userId = session?.user.id;
  const [toast, setToast] = useState<{message: string; visible: boolean}>({
    message: '',
    visible: false,
  });

  const handleNewNotification = useCallback((payload: Record<string, unknown>) => {
    const message =
      (payload.message as string) || 'You have a new notification';
    setToast({message, visible: true});
  }, []);

  const handleDismissToast = useCallback(() => {
    setToast(prev => ({...prev, visible: false}));
  }, []);

  useRealtimeNotifications(userId, {
    onNewNotification: handleNewNotification,
  });

  return (
    <View style={styles.shellContainer}>
      {children}
      <Toast
        message={toast.message}
        visible={toast.visible}
        onDismiss={handleDismissToast}
        type="info"
      />
    </View>
  );
}

export function RootNavigator() {
  const {loading, session} = useAuth();
  const {colors, isDark} = useTheme();

  const navTheme = useMemo(
    () => ({
      ...(isDark ? DarkTheme : DefaultTheme),
      colors: {
        ...(isDark ? DarkTheme.colors : DefaultTheme.colors),
        background: colors.bgPrimary,
        card: colors.bgElevated,
        border: colors.borderLight,
        text: colors.textPrimary,
        primary: colors.accentAmber,
        notification: colors.danger,
      },
    }),
    [colors, isDark],
  );

  if (loading) {
    return (
      <View style={[styles.loadingContainer, {backgroundColor: colors.bgPrimary}]}>
        <ActivityIndicator color={colors.loaderColor} />
        <Text style={[styles.loadingText, {color: colors.textMuted}]}>
          Loading session...
        </Text>
      </View>
    );
  }

  return (
    <NavigationContainer theme={navTheme}>
      <RootStack.Navigator
        screenOptions={{
          headerStyle: {backgroundColor: colors.bgElevated},
          headerTintColor: colors.textPrimary,
          headerShadowVisible: false,
          contentStyle: {backgroundColor: colors.bgPrimary},
        }}>
        {!session ? (
          <RootStack.Screen
            name="Auth"
            component={AuthNavigator}
            options={{headerShown: false}}
          />
        ) : (
          <>
            <RootStack.Screen
              name="Main"
              options={{headerShown: false}}>
              {() => (
                <LoggedInShell>
                  <MainTabNavigator />
                </LoggedInShell>
              )}
            </RootStack.Screen>
            <RootStack.Screen
              name="PostDetail"
              component={PostDetailScreen}
              options={{title: 'Post'}}
            />
            <RootStack.Screen
              name="JournalEditor"
              component={JournalEditorScreen}
              options={{title: 'Journal Editor'}}
            />
            <RootStack.Screen
              name="StoryDetail"
              component={StoryDetailScreen}
              options={{title: 'Story'}}
            />
            <RootStack.Screen
              name="StoryEditor"
              component={StoryEditorScreen}
              options={{title: 'Story Editor'}}
            />
            <RootStack.Screen
              name="StoryDashboard"
              component={StoryDashboardScreen}
              options={{title: 'My Stories'}}
            />
            <RootStack.Screen
              name="StoryLibrary"
              component={StoryLibraryScreen}
              options={{title: 'Story Library'}}
            />
            <RootStack.Screen
              name="StoryChapterManager"
              component={StoryChapterManagerScreen}
              options={{title: 'Chapter Manager'}}
            />
            <RootStack.Screen
              name="StoryChapterEditor"
              component={StoryChapterEditorScreen}
              options={{title: 'Chapter Editor'}}
            />
            <RootStack.Screen
              name="StoryChapterReader"
              component={StoryChapterReaderScreen}
              options={{title: 'Chapter'}}
            />
            <RootStack.Screen name="Canvas" component={CanvasScreen} />
            <RootStack.Screen
              name="FreedomWall"
              component={FreedomWallScreen}
              options={{title: 'Freedom Wall'}}
            />
            <RootStack.Screen name="Universe" component={UniverseScreen} />
          </>
        )}
      </RootStack.Navigator>
    </NavigationContainer>
  );
}

const styles = StyleSheet.create({
  shellContainer: {
    flex: 1,
  },
  loadingContainer: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
    gap: 8,
  },
  loadingText: {
    fontSize: 14,
  },
});

